class Solution:
    def minimumIndex(self, capacity, itemSize):
        # independent formulation: rank all qualifying (capacity, index) pairs and take the min
        candidates = [(c, i) for i, c in enumerate(capacity) if c >= itemSize]
        if not candidates:
            return -1
        return min(candidates)[1]

