class Solution:
    def minimumIndex(self, capacity, itemSize):
        best = -1
        best_cap = None
        for i, c in enumerate(capacity):
            if c >= itemSize and (best_cap is None or c < best_cap):
                best_cap = c
                best = i
        return best

